@ARTICLE{10.20047/j.issn1673-7210.2022.02.002,
	author = {胡丽萍 and 张存玉 and 王珊珊},
	title = {中外医学期刊英文摘要作者立场标记语对比研究},
	journal = {中国医药导报},
	year = {2022},
	keywords = {医学期刊; 英文摘要; 作者立场; 立场标记语 ER - ER - ER -},
	abstract = {目的 分析中外医学期刊作者立场标记语的使用特征和学术语篇功能。方法 从中国知网、科学引文索引数据库分别随机选取影响因子较高的中外医学期刊,从中摘取发表于2018—2019年论文的英文摘要,建立国内医学期刊英文摘要语料库和国际医学期刊英文摘要语料库,利用Ant Conc 3.5.8软件检索立场标记语在两个语料库中出现的频次,对比分析立场标记语在两个语料库的使用差异。结果 国际期刊的模糊语、增强语、态度标记语、自我指称语使用频次高于国内期刊(P <0.05);国际期刊模糊语中动词、副词、形容词的使用频次高于国内期刊,增强语中名词的使用频次高于国内期刊,态度标记语中态度动词、形容词的使用频次高于国内期刊,自我指称中“we”“our”的使用频次高于国内期刊(P <0.05);国际期刊作者立场标记语选词相对多样化,国内期刊较固化单一。结论 我国医学科研工作者能够合理使用立场标记语来建构自己的学术立场和学术身份,增强与读者之间的语篇互动,从而提升学术话语权并向世界传递中国医学声音。},
	doi = {10.20047/j.issn1673-7210.2022.02.002},
	type = {JOUR}
}

@ARTICLE{ris_000002,
	author = {于强福},
	title = {中外材料类期刊论文英文摘要中模糊限制语的对比分析},
	journal = {华北理工大学学报(社会科学版)},
	year = {2021},
	keywords = {模糊限制语; 英文摘要; 期刊论文; 对比分析 ER - ER - ER -},
	abstract = {文章旨在对比分析中外材料类期刊论文英文摘要中模糊限制语的使用特征,推动中国科技期刊英文摘要语言国际化、规范化,提升中国科技期刊国际影响力。选取中国科技期刊《材料工程》和国际期刊Advanced Materials英文摘要,构建两个小型语料库,使用语料库检索工具AntConc3.5.8对摘要各语步中的模糊限制语进行检索统计。结果显示,中外材料类期刊论文英文摘要中模糊限制语使用特征存在较大差距,中国期刊论文英文摘要模糊限制语使用频率低于国外期刊论文,存在过度使用某一类模糊限制语、过少使用某一类模糊限制语的现象;在英文摘要背景、结果、结论语步中模糊限制语使用方面,中国期刊论文与国际期刊论文也存在显著差异。文章认为,科技工作者应提高模糊限制语使用意识,在期刊论文、特别是英文摘要撰写过程中规范合理使用模糊限制语,提高论文的国际认可度和影响力。期刊编辑部可以通过制定期刊投稿指南、审稿过程关注微观语言特征等引导作者规范使用模糊限制语。},
	type = {JOUR}
}

@ARTICLE{ris_000003,
	author = {郑思琦 and 颜宏婧 and 张舒婷 and 万玲},
	title = {药学英语学术论文模糊限制语的人际意义研究},
	journal = {福建师大福清分校学报},
	year = {2021},
	keywords = {模糊限制语; 评价理论; 人际意义; 药学英语学术论文 ER - ER - ER -},
	abstract = {基于评价理论框架,采用Antconc软件检索和人工核验的方法,定量分析药学英语学术论文中介入型和极差型模糊限制语频率,定性分析作为不同评价资源模糊限制语的人际意义。研究发现,药学英语论文中介入型模糊限制语多于极差型模糊限制语。药学英语学术论文中,写作者运用不同的评价资源增加或者减少自己态度的介入,表达观点、协商态度并实现人际功能。},
	type = {JOUR}
}

@ARTICLE{ris_000004,
	author = {于强福},
	title = {基于语料库的机械工程类学术论文英文摘要中模糊限制语对比研究},
	journal = {华北理工大学学报(社会科学版)},
	year = {2021},
	keywords = {模糊限制语; 英文摘要; 硕士学位论文; 国际期刊论文; 语料库 ER - ER - ER -},
	abstract = {通过两个自建语料库,对比分析了机械工程类国内硕士学位论文与英语本族语学者撰写的国际核心期刊论文摘要中的模糊限制语。研究结果表明,国内研究生和英语本族语学者在使用模糊限制语的频率及类型上存在显著差异。针对国内机械工程类研究生在学位论文英文摘要写作过程中模糊限制语使用方面存在的问题,提出了相应的建议,以提高研究生学术英语写作过程中灵活使用模糊限制语的能力。},
	type = {JOUR}
}

@ARTICLE{ris_000005,
	author = {Mohammadi, S. and Sharafzadeh, M.H. and Hooshmand, M.},
	title = {Metadiscourse in Persian-text research articles: A comparative study on hard and soft sciences},
	journal = {International Journal of Language Studies},
	year = {2023},
	abstract = {The present study sought to find any probable differences between the various functions of metadiscursive hedging devices in the ‘discussions’ of Persian-text research articles (RAs) written by Iranian academic authors in hard and soft sciences. Sixty (N = 60) discussions from Persian-text Iranian academic journals (from five disciplines in hard sciences and four disciplines in soft sciences) were randomly selected. Two human coders were asked to code the functions of hedging devices in the selected corpus based on the theoretical framework suggested by Hyland (1998). Results indicated that authors of hard-science RAs prefer content-and reader-oriented hedging devices and use them more frequently in their RA discussions whereas their soft-science counterparts prefer writer-oriented hedging. It is argued that these differences might be due to (a) personality traits, (b) politeness, (c) the nature of hard and soft sciences, or (d) a combination of all of these. © 2023 IJLS. ER - ER - ER -},
	type = {JOUR}
}

@ARTICLE{10.1515/lpp-2019-0004,
	author = {Carrió-Pastor, M.L.},
	title = {Different ways to express personal attitudes in Spanish and English engineering papers: An analysis of metadiscourse devices, affective evaluation and sentiment analysis},
	journal = {Lodz Papers in Pragmatics},
	year = {2020},
	abstract = {The hypothesis of this paper is that writers with similar academic backgrounds express personal attitudes in English and in Spanish differently in research papers. Thus, the main objectives are, first, to study the differences in the use of attitude devices in Spanish and English academic discourse; second, to compare the results in the different sections of articles; and finally to study the positive or negative semantic implications of the lexical items by carrying out a sentiment analysis. To this end, fifteen Spanish industrial engineering papers were compared with fifteen English industrial engineering papers. The results showed that there are in fact differences in the way academic writers communicate attitude, but the sentiment analysis revealed that neutral lexical items were the most commonly used in engineering research papers. Even though engineering researchers share the knowledge of the specialist content and the academic style of expressing their thoughts, personal attitudes were expressed in different ways in Spanish and in English. © 2019 Walter de Gruyter GmbH, Berlin/Boston 2019. ER - ER - ER -},
	doi = {10.1515/lpp-2019-0004},
	type = {JOUR}
}

@ARTICLE{10.47012/jjmll.13.2.5,
	author = {Farnia, M. and Gerami, S.},
	title = {Ne* comparative study of interactional metadiscourse markers in the discussion section of soft and hard science research articles: Hedges and boosters in focus *},
	journal = {Jordan Journal of Modern Languages and Literatures},
	year = {2021},
	abstract = {The aim of this descriptive analytical study was to examine research articles discussion sections from four disciplines to measure the functions and frequencies of hedges and boosters. To this end, scholarly research articles were randomly selected from leading and reputable journals in mechanical and industrial engineering as representatives of hard science disciplines and management and psychology as representatives of soft science disciplines. The size of the corpus in each discipline was around 17000 words. The data were analyzed in light of Hyland's (2005) model of interactional metadiscourse for hedges and boosters devices. Results of descriptive and inferential statistics showed that the use of hedges was significantly more in soft science disciples while boosters were overused in hard science disciplines, corresponding to the fact that by virtue of being less personal and more objective, hard sciences are represented through more frequent use of boosters than hedges to express facts. On the other hand, soft sciences are influenced by their subjectivity which results in higher frequencies of hedges. The findings of this study have implications for English for Academic/Specific purposes courses. © 2021 JJMLL Publishers/Yarmouk University. All Rights Reserved,. ER - ER - ER -},
	doi = {10.47012/jjmll.13.2.5},
	type = {JOUR}
}

@ARTICLE{10.5430/wjel.v15n2p342,
	author = {Jovic, M. and Levidze, M. and García, B.G.},
	title = {Hedging in Medical Articles from Two Pandemics},
	journal = {World Journal of English Language},
	year = {2025},
	abstract = {As academic and scientific disciplines continue to evolve, it remains essential for scholars to present their claims with caution. Hedging, a vital linguistic tool, is pervasive in academic writing, although its boundaries are not strictly defined. This research tracks the changes in the use of hedging within medical literature, underpinning the idea that linguistic patterns reflect societal changes. Our study focuses on the analysis of hedging devices within a corpus of 30 medical articles, spanning two distinct pandemic periods: the 1918-1919 influenza pandemic and the 2020-2021 COVID-19 pandemic. A comprehensive review, involving contextual analysis, was conducted for each article to identify hedging instances. Types of hedges were documented and their frequency was calculated, while ambiguous cases were clarified through in-depth discussions and consistency checks. Our analysis confirms that contextual conditions influence both the frequency and types of hedges used. The results show a significant decrease in overall hedging frequency between the two pandemic periods, with approximators declining sharply while shields remained stable. This shift, along with a reduction in the variety of hedging devices used, suggests an evolution towards more precise quantification and a more formulaic style in scientific writing, while maintaining caution in knowledge claims. The conclusions drawn in this paper contribute to our understanding of scientific discourse and its evolution. © 2025 Sciedu Press. All rights reserved. ER - ER - ER -},
	doi = {10.5430/wjel.v15n2p342},
	type = {JOUR}
}

@ARTICLE{10.4000/lidil.10575,
	author = {Carrió-Pastor, M.L.},
	title = {Teaching Multimodal Metadiscourse in English for Academic Purposes},
	journal = {Lidil},
	year = {2022},
	abstract = {On the one hand, metadiscourse consists of discourse markers that do not add propositional content to discourse. On the other, multimodality is based on a functional analysis of language and includes all semiotic systems and resources. The two fields of knowledge make up multimodal metadiscourse. As both text and images are useful to guide readers in English for academic purposes (EAP), I included them in this analysis on multimodal metadiscourse performed for teaching purposes. The main objectives of this paper are, first, to identify the textual and visual metadiscourse devices used by EAP learners enrolled in an engineering degree and by engineers in research papers. The second is to compare the frequencies of the multimodal metadiscourse devices used by engineering learners and researchers in order to propose some hints that may be useful for EAP teachers. To this end, I compiled and analysed two corpora: one made up of research papers and the other consisting of material written by English learners, both on engineering. The results showed the features of multimodal metadiscourse still to be acquired by EAP learners. After that, some tips were suggested for the design of activities taking into account the results and examples extracted from the analysis of the two corpora. Finally, conclusions were drawn on the most frequent multimodal metadiscourse devices used and their possible use in teaching EAP. © 2022 Universite Stendhal, Editions Litteraires et Linguistiques de l'Universite de Grenoble (ELLUG). All rights reserved. ER - ER - ER -},
	doi = {10.4000/lidil.10575},
	type = {JOUR}
}

@ARTICLE{10.5817/di2022-2-5,
	author = {Boginskaya, O.A.},
	title = {METADISCOURSE PATTERNS IN ACADEMIC PROSE BY NON-NATIVE ENGLISH WRITERS: A CROSS-DISCIPLINARY PERSPECTIVE},
	journal = {Discourse and Interaction},
	year = {2022},
	abstract = {This article scrutinizes metadiscourse in English-medium academic prose by Russian writers from two different discourse communities focusing on the ways they interact with the reader and present themselves and their research results. It is assumed that the distribution of interactional metadiscourse elements varies across disciplines. The theoretical basis of the study is Hyland’s (2005) model of interactional metadiscourse which offers a pragmatically-grounded method of studying metadiscourse in academic texts. The study was carried out on a corpus of 156 abstracts derived from two Russian journals in the field of linguistics and computer engineering. The study confirmed Hyland’s findings about research article abstracts in the humanities and hard sciences, though it revealed some distinctive features of English-medium research article abstracts by Russian writers. The findings can enhance English L2 novice academic writers’ familiarity with the academic writing conventions in the discipline. © 2022 Masaryk University. All rights reserved. ER - ER - ER -},
	doi = {10.5817/di2022-2-5},
	type = {JOUR}
}

@ARTICLE{10.21638/spbu09.2023.211,
	author = {Boginskaya, O.A.},
	title = {Lexical realizations of hedging: A cross-disciplinary study of research article abstracts by Russian authors},
	journal = {Vestnik Sankt-Peterburgskogo Universiteta, Yazyk i Literatura},
	year = {2023},
	abstract = {Currently, when the English language has established itself as a lingua franca in academic settings, it is relevant to investigate rhetorical strategies in texts produced by L2 writers who use English in their academic prose. This paper explores lexical patterns of hedging in Englishmedium research article abstracts written by L2 (Russian) writers from two fields representing hard sciences and humanities — engineering and linguistics. The main focus is on quantitative and qualitative variations in the lexical realizations of hedging as a metadiscourse strategy used to present research results and enter into a dialogue with the reader. The corpus comprises 312 engineering and linguistics research article abstracts taken equally from six Russian linguistic and engineering journals. In order to investigate hedging devices and their lexical categories, this study adopted the methods of quantitative and qualitative analysis. The results of the quantitative analysis show that there are many differences in the distribution of lexical patterns of hedging in the two sub-corpora. In the engineering abstracts, hedging was most frequently realized through modal auxiliaries and adverbs of frequency. In the linguistics subcorpus, probability nouns and reporting verbs were among the most frequent lexical patterns of hedging. In the linguistics abstracts, hedging was realized through a greater variety of lexical categories. This suggests that lexical realizations of hedging seem to be influenced by the discipline rather than generic conventions. © St. Petersburg State University, 2023. ER - ER - ER -},
	doi = {10.21638/spbu09.2023.211},
	type = {JOUR}
}

@ARTICLE{10.1515/opli-2022-0229,
	author = {Schmauss, L.S. and Kilian, K.},
	title = {Hedging with modal auxiliary verbs in scientific discourse and women's language},
	journal = {Open Linguistics},
	year = {2023},
	abstract = {This Critical Discourse Analysis examines hedging as a linguistic device at the intersection of scientific discourse and women's language. Hedging has been identified as a marker of scientific discourse where it is valued for expanding dialogic space for the promulgation of knowledge. It is also a recognised marker of women's common language, where it is purported to align with discriminatory gender norms that women should not impose their views but could also be construed as a lack of clear thinking, conviction, or confidence. This could be limiting, especially in professional domains, however, the particular value attached to hedging in scientific discourse challenges this hypothesis and provides the focus of this study of gender differences in hedging with modal auxiliary verbs in the context of scientific discourse. The findings confirm hedging as a marker of scientific discourse and reflect modal auxiliaries being used with similar frequency by women and men, although with subtle, but significant differences in the specific modals that were used, and how. This provides a nuanced picture of women hedging in ways that mostly exemplify the standards of scientific discourse while also integrating some of the socially normative hedging practices that are associated with women's language. © 2023 the author(s), published by De Gruyter. ER - ER - ER -},
	doi = {10.1515/opli-2022-0229},
	type = {JOUR}
}

@ARTICLE{10.22363/2521-442x-2022-6-3-55-66,
	author = {Boginskaya, O.A.},
	title = {Cross-disciplinary variation in metadiscourse: A corpus-based analysis of Russian-authored research article abstracts},
	journal = {Training, Language and Culture},
	year = {2022},
	abstract = {The article deals with metadiscourse variation in academic texts across disciplinary boundaries. Its main focus is on the distribution of metadiscourse markers in Russian-authored academic prose in the field of applied linguistics and engineering. The study assumes that the distribution of metadiscourse devices is determined by disciplinary norms. The theoretical basis of the study is Hyland’s taxonomy of metadiscourse markers. With the aim of investigating metadiscourse in English-medium research article (RA) abstracts by Russian authors, the present study adopted a combination of quantitative and qualitative methods. The results revealed that RA abstracts feature four types of metadiscourse markers whose distribution varies across two disciplines representing the humanities and hard sciences. The study also investigated the degree of familiarity of linguistics and engineering scholars from leading Russian universities with metadiscourse devices and their awareness of the need to use them in research articles. To achieve this goal, a survey was conducted to obtain data on knowledge of metadiscourse as a discursive strategy. The findings carry therefore pedagogical implications for academic writing course designers and instructors and can enhance non-native English writers’ knowledge of academic writing conventions in the discipline. © Olga A. Boginskaya 2022. ER - ER - ER -},
	doi = {10.22363/2521-442x-2022-6-3-55-66},
	type = {JOUR}
}

@ARTICLE{10.31902/fll.42.2022.16,
	author = {Radojičić, S. and Novakov, P.},
	title = {Hedging and Boosting Strategies in Linguistics and Geography – A Case Study of Student Perception},
	journal = {Folia Linguistica et Litteraria},
	year = {2022},
	abstract = {This paper examines the use of hedging and boosting strategies in written academic discourse, specifically in scientific/research monographs in Linguistics and Geography. In particular, hedging and boosting strategies in academia are analysed within the corpora of monographs written in the two abovementioned disciplines in English and in Serbian, in order to investigate the possible differences in the interactional discipline-specific practices. Moreover, the paper explores student perceptions of the hedging and boosting used in the written scientific discourse in both Linguistics and Geography. This pilot study, conducted at the University of Novi Sad, focuses on the student reception of the hedging and boosting used in the scientific monograph corpora in the field of Linguistics and Geography in English and Serbian. Our findings show that focusing on hedging and boosting strategies in academic discourse in the English and in the Serbian corpora helps students achieve a better understanding of the discourse. We propose that exposing students to various samples of scientific writing and guiding them through the examination of the discipline-specific usage of hedges and boosters could benefit both students and language instructors. Students would better understand the intentions and implications of the authors’ scientific discourses if they were given a comparison of the English and Serbian discipline-specific hedging and boosting strategies. If language instructors were to focus students’ attention on the language-specific features used in scientific discourse, it would improve students’ understanding of scientific inquiry and scientific methodologies. Guiding students through the rules of hedging and boosting would most likely enable them to better locate hedging and boosting within the existing body of literature, to reflect upon the credibility of scientific findings, and to integrate such strategies into their future academic and professional writing. © 2023 Universidade Federal de Goias. All rights reserved. ER - ER - ER -},
	doi = {10.31902/fll.42.2022.16},
	type = {JOUR}
}

@ARTICLE{10.1016/j.jeap.2026.101640,
	author = {Yao, G. and Liu, Z.},
	title = {Rhetorical divergence of AI: Comparing interactive and interactional metadiscourse in GPT-generated and human-authored research abstracts across disciplines},
	journal = {Journal of English for Academic Purposes},
	year = {2026},
	abstract = {Academic writing is inherently social and persuasive, relying on metadiscourse to mediate interaction between writers and readers. The emergence of Large Language Models (LLMs) such as ChatGPT challenges this dynamic, raising questions about their ability to reproduce human rhetorical complexity. Although previous studies have noted AI's limitations in interactional features, a comprehensive cross-disciplinary analysis of both interactive and interactional metadiscourse in empirical research article (RA) abstracts remains underexplored. Given that abstracts play a crucial gatekeeping role by shaping first impressions and influencing readership, understanding how AI deploys organizational and persuasive language in this genre is essential. Addressing this gap, the present study offers a systematic comparative analysis of metadiscourse use in ChatGPT-generated and human-authored RA abstracts across Engineering, Medicine, and Applied Linguistics. Using a novel methodology that integrates corpus linguistics with computational semantic modeling (BERT embeddings and t-SNE visualization), the analysis moves beyond frequency counts to examine meaning in context. Findings indicate that AI-generated abstracts place greater emphasis on explicit textual organization through interactive metadiscourse, sometimes exceeding human usage of features such as code glosses and evidentials. However, AI demonstrates marked weaknesses in interactional metadiscourse, including limited stance modulation and reduced personal engagement, particularly through the underuse of self-mentions and inconsistent use of hedges across disciplines. Moreover, AI shows limited sensitivity to discipline-specific rhetorical norms. These results suggest that current AI models fall short of replicating the interpersonal and disciplinary sophistication of expert academic writing, offering implications for AI detection and academic writing pedagogy. Copyright © 2026. Published by Elsevier Ltd. ER - ER - ER -},
	doi = {10.1016/j.jeap.2026.101640},
	type = {JOUR}
}

@ARTICLE{10.1080/13825577.2021.1988254,
	author = {Carrió-Pastor, M.L.},
	title = {Multimodal metadiscourse in digital academic journals on linguistics, engineering and medicine},
	journal = {European Journal of English Studies},
	year = {2021},
	abstract = {The main objectives of this study are, first, to analyse the interactive metadiscourse devices used in engineering, medicine and linguistics and the identities represented; second, to identify the visual metadiscourse elements employed in the three identities constructed in the three specific settings and, finally, to classify and compare the multimodal metadiscourse used to cohere the different parts of digital academic discourse with the aim of guiding the reader textually as well as visually. To this end, academic papers were collected from journals which belonged to the specific fields of linguistics, engineering and medicine. The corpus was analysed to identify and classify the data. The results showed that there were in fact differences in the way academic writers used multimodal metadiscourse and constructed and represented their identity. The study revealed that engineers used visual metadiscourse more frequently, while linguistic researchers preferred the use of textual metadiscourse. Finally, conclusions were drawn. © 2021 Informa UK Limited, trading as Taylor & Francis Group. ER - ER - ER -},
	doi = {10.1080/13825577.2021.1988254},
	type = {JOUR}
}

@ARTICLE{10.5209/clac.81305,
	author = {Navarro, F. and Montes, S. and Álvarez, M.},
	title = {How do students write in engineering and the humanities? Intertextuality and metadiscourse in undergraduate dissertations written in Spanish},
	journal = {Circulo de Linguistica Aplicada a la Comunicacion},
	year = {2022},
	abstract = {This article aims to contrast metadiscourse and intertextuality in 40 undergraduate dissertations written in Spanish in engineering and the humanities at a Chilean university. Results show that guidance on dissertations’ goals and stages is common across disciplines, especially in introductions, although engineering signals goals more often. All students graduate statements, especially in conclusions, but the frequency of graduation doubles in the humanities. Humanities students prefer hedging over boosting, while boosting is more common in engineering. Self-mentions, especially plural authorial, are frequent in the humanities but do not occur in engineering. Citations are five times more frequent and usually integral in the humanities, while engineering only uses non-integral citations. Indirect speech predominates across disciplines, but direct and mixed speech are also relatively common in the humanities. This study can help to understand undergraduate students’ authorial voices written in Spanish, depict discipline-specific writing choices, and supply data for writing instruction initiatives. © 2022 Universidad Complutense de Madrid. All rights reserved. ER - ER - ER -},
	doi = {10.5209/clac.81305},
	type = {JOUR}
}

@ARTICLE{10.15443/rl3415,
	author = {Boginskaya, O.},
	title = {How to avoid potential rejection on the part of the reader: lexical realizations of hedging as a politeness strategy in academic prose},
	journal = {Logos: Revista de Linguistica, Filosofia y Literatura},
	year = {2024},
	abstract = {The study aims to consider hedging as a politeness strategy used to appear humble rather than all-knowing in academic interaction. Hedging has yielded a lot of attention as the main strategy used to show politeness and mitigate face-threats in academic prose. Studies have explored it from different perspectives, yet few ones have been conducted on lexical patterns of hedging in academic writing from a cross-disciplinary perspective. Drawing on a corpus of 412 research article abstracts taken from the five journals in each of the four disciplines (linguistics, law, engineering, and medicine), this article seeks to describe an interdisciplinary comparison of lexical patterns used to show politeness in academic texts. The study proceeds from Myer’s (1989) pragmatically-oriented concept of hedging devices as signs of politeness used to avoid categorical statements. Vartalla’s (2001) taxonomy of lexical realizations of hedging was taken as a point of departure. The quantitative analysis indicated that the distribution of lexical patterns used to show politeness differed across disciplines. © 2024 Universidad de la Serena,Departamento de Artes y Letras. All rights reserved. ER - ER - ER -},
	doi = {10.15443/rl3415},
	type = {JOUR}
}

@ARTICLE{10.1016/j.amper.2025.100238,
	author = {Khamkhien, A.},
	title = {Disciplinary variation in argumentative essays: Mapping metadiscourse patterns in undergraduate writing},
	journal = {Ampersand},
	year = {2025},
	abstract = {Academic writing is not only content-oriented but also involves various rhetorical strategies that enable authors to project themselves into the text. This study investigated the use of metadiscourse markers in 230 undergraduate argumentative essays across four disciplines: health and human sciences, liberal arts, science, and engineering, drawing on Hyland's (2005) model to examine interactive and interactional resources. The analysed essays were taken from undergraduate students with diverse L1 backgrounds in the CROW corpus. A mixed-methods approach was employed, combining frequency analysis using corpus tools (SketchEngine) with manual annotation and statistical testing to identify patterns of metadiscourse across discipline and educational contexts. Specifically, interactive markers, particularly transitions and frame markers, dominated all disciplines, reflecting students' textual cohesion and organisation prioritisation. Interactional markers such as hedges and engagement devices were used more selectively as science and engineering students favoured precise, low-reflexivity strategies. Likewise, liberal arts and health students used more evaluative language and authorial presence. Pedagogically, this study highlights the importance of explicit instruction on metadiscourse, emphasising genre and discipline-sensitive approaches to guiding readers, taking a personal stance, and engaging directly with readers. © 2025 The Author ER - ER - ER -},
	doi = {10.1016/j.amper.2025.100238},
	type = {JOUR}
}

@ARTICLE{10.1590/1984-6398202422953,
	author = {Ferrer, R.},
	title = {Metadiscourse Features in Aeronautics and Aerospace Engineering: The Use of Interactive and Interactional Markers},
	journal = {Revista Brasileira de Linguistica Aplicada},
	year = {2024},
	abstract = {Several studies on metadiscourse zero in on how genres show nuances of linguistic features that reside in various structures depending upon the linguistic exigencies of language for specific purposes. Inquisitive on how these nuances are demonstrated through a repertoire of metadiscoursal features in a highly contextualized discourse, this paper explores how metadiscourse resources are utilized in aeronautics and aerospace engineering and how these facilitate the development of a well-composed text in the field of aviation. Using Hyland and Tse’s (2004) and Hyland’s (2005, 2010) analytical frameworks for interactive and interactional resources, a corpus of thirty research articles comprising 125,298 words published in the Journal of Aeronautics and Aerospace Engineering was scrutinized. As revealed in the study, the investigated metadiscourse markers resembled Hyland and Tse’s (2004) and Hyland’s (2005, 2010) findings in terms of interactive and interactional markers, which contain similar features of academic writing such as formality and objectivity; however, in the use of interactional resources, it yielded a finding that supports informality through the use of self-mentions. The quantitative analysis yielded a higher frequency of interactive markers than interactional markers across the thirty articles. This argues that writers in aeronautics and aerospace engineering articles essentially employ more interactive resources than interactional resources, suggesting that these writers are primarily concerned with making their text more cohesive while being responsible for establishing an interpersonal stance toward both the propositional contents and the audience of the text. The findings of the present study provide pedagogical implications as to how writers in the field of aeronautics and aerospace engineering can effectively compose their articles through the strategic use of metadiscoursal markers. © 2024, Universidade Federal de Minas Gerais, Faculdade de Letras. All rights reserved. ER - ER - ER -},
	doi = {10.1590/1984-6398202422953},
	type = {JOUR}
}

@ARTICLE{10.1007/s11192-021-04064-0,
	author = {Deng, L. and Fatemeh, B. and Gao, X.},
	title = {Exploring the interactive and interactional metadiscourse in doctoral dissertation writing: a diachronic study},
	journal = {Scientometrics},
	year = {2021},
	abstract = {This study explores the diachronic evolution of doctoral dissertation writing in terms of interactive and interactional metadiscourse at three time intervals of 1966, 1986, and 2016 through examining the salient textual features and the pattern of change involved in the metadiscourse in question. One hundred and eighty authentic doctoral dissertations were retrieved from humanities and social sciences (HSS) and sciences and engineering (SE) which generated a 5.16 million words corpus. Findings show that metadiscourse has considerably increased for SE and drastically decreased for HSS. Therefore, it is claimed that academic writing tends to be moving toward more objective and audience responsible texts in HSS and less objective and more author responsible texts in SE. This suggests that the former is inclined to get less persuasive and reader-oriented while the latter appears to be more persuasive and reader-friendly. Based on the findings, a theoretical model of academic writing evolution is proposed which focuses on three writing aspects, namely, informality and subjectivity, reader-orientedness and persuasiveness in the hope of offering implications for better understanding and constructing academic writing across disciplines. © 2021, Akadémiai Kiadó, Budapest, Hungary. ER - ER - ER -},
	doi = {10.1007/s11192-021-04064-0},
	type = {JOUR}
}

@ARTICLE{10.1002/leap.1515,
	author = {Xie, S. and Mi, C.},
	title = {Promotion and caution in research article abstracts: The use of positive, negative and hedge words across disciplines and rankings},
	journal = {Learned Publishing},
	year = {2023},
	abstract = {Abstract as a promotional genre has been an increasing interest in recent years, leading to an intriguing debate on the objectivity of scientific writing. The present study investigated the promotion and caution in research article abstracts through the use of positive, negative and hedge words across disciplines and rankings based on a large and principled dataset (more than 12.6 million words). The corpus was designed and built with full consideration of representativeness, structure, balance, and size in terms of discipline and ranking. The results showed that positive words were more frequently used than negative words in terms of both discipline and ranking, positive and negative words were more frequently used in hard sciences than those in soft sciences and high ranking journals than those in low ranking journals, and hedge words were more frequently used in high ranking journals and soft sciences. Further investigation also found a complexity of frequency patterns when two disciplines were broken down into specific categories. The more frequent use of positive words in abstracts to promote scientific research was discussed from the perspective of disciplinary knowledge construction in addition to the publication bias, the outcome reporting bias, and universal linguistic positivity bias. © 2023 The Authors. Learned Publishing © 2023 ALPSP. ER - ER - ER -},
	doi = {10.1002/leap.1515},
	type = {JOUR}
}

@ARTICLE{10.1016/j.linged.2026.101507,
	author = {Yang, C. and Guo, Y. and Shao, J. and Zhang, L. and Jiang, F.K.},
	title = {Rhetorical evolution in mathematical modelling: A diachronic analysis of metadiscourse in MCM/ICM contest papers},
	journal = {Linguistics and Education},
	year = {2026},
	abstract = {This study investigates diachronic changes in metadiscourse within a relatively under-researched STEM genre: Mathematical Contest in Modelling (MCM) and Interdisciplinary Contest in Modelling (ICM) reports. Focusing on introduction sections, where writers must frame the problem, justify modelling choices, and persuade judges of the significance of their approach, we examine how student writers adapt rhetorical strategies in response to evolving evaluative demands. A corpus of 120 award-winning papers across two timeframes (2004–2013 and 2014–2023) was analysed using Hyland’s (2005a) model of interactive and interactional metadiscourse. Corpus searches were supplemented with functional coding to capture genre-specific forms. Results show a notable rise in engagement markers and boosters, accompanied by a decline in hedges and attitude markers. These trends indicate a shift toward more reader-oriented and assertive discourse, reflecting both broader developments in STEM communication and the contests’ particular communicative demands, where informative exposition is combined with persuasive promotion. The findings highlight the distinctive rhetorical identity of MCM/ICM introductions, which differ from other sections such as conclusions, and from conventional STEM writing more broadly. By tracing rhetorical evolution across two decades, the study demonstrates how student writers negotiate credibility, coherence, and persuasion within highly competitive contexts. The study contributes to ESP research by clarifying how genre- and section-specific pressures shape metadiscourse use. Pedagogically, it underscores the value of explicit instruction in the persuasive deployment of metadiscourse resources, helping STEM students develop rhetorical awareness alongside technical competence. © 2026 Elsevier Inc. ER - ER - ER -},
	doi = {10.1016/j.linged.2026.101507},
	type = {JOUR}
}

@ARTICLE{10.18485/esptoday.2022.10.2.3,
	author = {Limnios, O.A.},
	title = {FICTIONALITY MARKERS IN PROFESSIONAL SCIENTIFIC ARTICLES: A NEW APPROACH TO HEDGING},
	journal = {ESP Today},
	year = {2022},
	abstract = {The present study is concerned with a select set of hedges – linguistic markers of stance. However, instead of accepting the functions of these constructs exclusively as indicators of uncertainty or negative politeness (Hyland, 1998; Varttala, 1999), I argue that in many cases hedges may be locations for fictionality. Later research already points to additional subfunctions of hedges (Aull & Lancaster 2014; Hyland, 2005; Hyland & Jiang, 2016; Lancaster, 2016a, 2016b). Data collected from 15 professional scientific articles (a corpus of 144,520 words) was examined for presence of the additional subfunction of fictionality. The phenomenon of fictionality in non-fiction is identified by Skov Nielsen, Phelan, and Walsh (2015a) as “what-if projections, if-only regrets, thought experiments, and hypotheses of all kinds.” In the process of examining instances of fictionality signaled by hedges, I identified the parameters of Real Condition and Fictional Condition each determined by context, verbal process types, and the number of hedging devices used. Real Condition embodies the already established functions of hedges, while Fictional Condition points to a new dialogic subfunction associated with fictionality. This exploratory study invites further research into functional aspects of hedging and raises awareness of fictionality in professional scientific writing. © 2022. ESP Today.All Rights Reserved ER - ER - ER -},
	doi = {10.18485/esptoday.2022.10.2.3},
	type = {JOUR}
}
